<!DOCTYPE html>
<html lang="en">
<head>
    <meta charset="UTF-8" />
    <title>Conway's Game of Life</title>
    <style>
        body {
            background: #121212;
            color: white;
            font-family: sans-serif;
            display: flex;
            flex-direction: column;
            align-items: center;
            justify-content: center;
            height: 100vh;
            margin: 0;
        }
        canvas {
            border: 1px solid #444;
            background: #2e2e2e;
            image-rendering: crisp-edges;
        }
        .controls {
            margin-top: 15px;
        }
        button {
            padding: 8px 16px;
            margin: 0 5px;
            font-size: 14px;
            background: #3e3e3e;
            color: white;
            border: none;
            cursor: pointer;
            border-radius: 4px;
        }
        button:hover {
            background: #555;
        }
    </style>
</head>
<body>
    <canvas id="life" width="400" height="400"></canvas>
    <div class="controls">
        <button id="step">Step</button>
        <button id="play">Play</button>
        <button id="random">Random</button>
        <button id="clear">Clear</button>
    </div>

    <script>
        const canvas = document.getElementById('life');
        const ctx = canvas.getContext('2d');
        const w = 40;
        const h = 40;
        let grid = [];

        function createGrid() {
            return new Array(w).fill(0).map(() => new Array(h).fill(0));
        }

        grid = createGrid();

        window.life = {
            w,
            h,
            get(x, y) {
                if (x >= 0 && x < this.w && y >= 0 && y < this.h) return grid[x][y];
                return 0;
            },
            set(x, y, v) {
                if (x >= 0 && x < this.w && y >= 0 && y < this.h) {
                    grid[x][y] = v ? 1 : 0;
                    draw();
                }
            },
            step() {
                const newGrid = createGrid();
                for (let x = 0; x < w; x++) {
                    for (let y = 0; y < h; y++) {
                        const alive = grid[x][y];
                        const neighbors = countNeighbors(x, y);
                        if (alive) {
                            newGrid[x][y] = (neighbors === 2 || neighbors === 3) ? 1 : 0;
                        } else {
                            newGrid[x][y] = (neighbors === 3) ? 1 : 0;
                        }
                    }
                }
                grid = newGrid;
                draw();
            },
            clear() {
                for (let x = 0; x < w; x++) {
                    for (let y = 0; y < h; y++) {
                        grid[x][y] = 0;
                    }
                }
                draw();
            }
        };

        function countNeighbors(x, y) {
            let count = 0;
            for (let dx of [-1, 0, 1]) {
                for (let dy of [-1, 0, 1]) {
                    if (dx === 0 && dy === 0) continue;
                    count += window.life.get(x + dx, y + dy);
                }
            }
            return count;
        }

        function draw() {
            const cellSize = canvas.width / w;
            ctx.clearRect(0, 0, canvas.width, canvas.height);
            for (let x = 0; x < w; x++) {
                for (let y = 0; y < h; y++) {
                    if (grid[x][y]) {
                        ctx.fillStyle = '#4caf50';
                        ctx.fillRect(x * cellSize, y * cellSize, cellSize, cellSize);
                    }
                }
            }
        }

        draw();

        let isMouseDown = false;

        canvas.addEventListener('mousedown', e => {
            const rect = canvas.getBoundingClientRect();
            const x = e.clientX - rect.left;
            const y = e.clientY - rect.top;
            toggleCell(x, y);
            isMouseDown = true;
        });

        canvas.addEventListener('mousemove', e => {
            if (!isMouseDown) return;
            const rect = canvas.getBoundingClientRect();
            const x = e.clientX - rect.left;
            const y = e.clientY - rect.top;
            toggleCell(x, y);
        });

        canvas.addEventListener('mouseup', () => isMouseDown = false);
        canvas.addEventListener('mouseleave', () => isMouseDown = false);

        function toggleCell(x, y) {
            const cellSize = canvas.width / w;
            const col = Math.floor(x / cellSize);
            const row = Math.floor(y / cellSize);
            window.life.set(col, row, grid[col][row] ? 0 : 1);
        }

        document.getElementById('step').addEventListener('click', () => window.life.step());

        let running = false;
        let intervalId;

        document.getElementById('play').addEventListener('click', () => {
            if (running) {
                clearInterval(intervalId);
                running = false;
                document.getElementById('play').textContent = 'Play';
            } else {
                running = true;
                intervalId = setInterval(() => window.life.step(), 100);
                document.getElementById('play').textContent = 'Pause';
            }
        });

        document.getElementById('random').addEventListener('click', () => {
            const newGrid = createGrid();
            for (let x = 0; x < w; x++) {
                for (let y = 0; y < h; y++) {
                    newGrid[x][y] = Math.random() < 0.2 ? 1 : 0;
                }
            }
            grid = newGrid;
            draw();
        });

        document.getElementById('clear').addEventListener('click', () => window.life.clear());
    </script>
</body>
</html>
